import React from 'react';
import { FiPlus, FiUsers, FiWifi } from 'react-icons/fi';

const rooms = [
	{
		id: 1,
		name: 'Lecture Hall A',
		type: 'Lecture Hall',
		seats: 150,
		status: 'Available',
		features: ['Projector', 'Audio System', 'Whiteboard'],
	},
	{
		id: 2,
		name: 'Seminar Room 3',
		type: 'Seminar Room',
		seats: 30,
		status: 'Occupied',
		features: ['Smart TV', 'Video Conf'],
	},
	{
		id: 3,
		name: 'Lab 4B',
		type: 'Laboratory',
		seats: 40,
		status: 'Maintenance',
		features: ['Workstations', 'Specialized Eq.'],
	},
	{
		id: 4,
		name: 'Conference Room',
		type: 'Meeting Room',
		seats: 20,
		status: 'Available',
		features: ['Projector', 'Whiteboard'],
	},
	{
		id: 5,
		name: 'Study Pod 12',
		type: 'Study Space',
		seats: 4,
		status: 'Available',
		features: ['Monitor', 'Power Outlets'],
	},
	{
		id: 6,
		name: 'Main Auditorium',
		type: 'Auditorium',
		seats: 500,
		status: 'Available',
		features: ['Full AV Setup', 'Stage'],
	},
];

const statusClass = (status) => {
	if (status === 'Available') return 'room-status available';
	if (status === 'Occupied') return 'room-status occupied';
	return 'room-status maintenance';
};

const ResourceList = () => {
	return (
		<div className="rooms-page">
			<div className="rooms-header">
				<div>
					<h1>Room Management</h1>
					<p>View and manage campus facilities and capacities.</p>
				</div>

				<button type="button" className="add-room-btn">
					<FiPlus />
					<span>Add Room</span>
				</button>
			</div>

			<div className="rooms-grid">
				{rooms.map((room) => (
					<article className="room-card" key={room.id}>
						<div className="room-card-header">
							<div>
								<h3>{room.name}</h3>
								<p>{room.type}</p>
							</div>
							<span className={statusClass(room.status)}>{room.status}</span>
						</div>

						<div className="room-meta">
							<span>
								<FiUsers /> {room.seats} Seats
							</span>
							<span>
								<FiWifi /> Wi-Fi
							</span>
						</div>

						<div className="room-features">
							<p>Features</p>
							<div>
								{room.features.map((feature) => (
									<span key={feature} className="feature-chip">
										{feature}
									</span>
								))}
							</div>
						</div>

						<div className="room-actions">
							<button type="button" className="room-edit-btn">Edit</button>
							<button type="button" className="room-schedule-btn">Schedule</button>
						</div>
					</article>
				))}
			</div>
		</div>
	);
};

export default ResourceList;
